UPDATE coaching.exercise SET
  name = 'Line Pogo Hops',
  description = 'Line Pogo Hops is a elastic stiffness and foot reactivity drill. The athlete uses clear start, plant, stop, or exit targets to rehearse two-foot vertical stiffness before cuts, emphasizing low hips, clean foot placement, aligned braking, and an immediate reacceleration or stable stick depending on the drill intent.',
  card_summary = 'Line Pogo Hops targets two-foot vertical stiffness before cuts for athletes who need fast stops, sharp cuts, and explosive reacceleration. It was selected for football receivers, soccer players, lacrosse players, and other field-sport athletes who need dynamic shiftiness without sacrificing joint control.',
  coach_language = 'Primary subrole: potentiate_bridge. Use this card for elastic stiffness and foot reactivity. Coach the entry, plant, and exit as separate qualities before blending them into faster sport-like reps.',
  athlete_language = 'Brake clean, own the edge, then explode out.',
  movement_family = 'Elastic Foot & Ankle Prep',
  primary_phase_key = 'prepare_and_access',
  phase_subrole = 'potentiate_bridge',
  primary_order_slot = 'elastic_prep',
  default_sets = 2,
  default_reps = 20,
  default_work_seconds = 20,
  default_rest_seconds = 20,
  est_seconds_per_set = 40,
