  coaching_execution = '{"movement_description":"Line Pogo Hops develops two-foot vertical stiffness before cuts for field and court athletes who need abrupt stops, quick redirection, and explosive reacceleration while preserving posture and joint alignment.","setup":["Use a flat, dry surface with enough clear space for the prescribed approach and exit.","Mark start, plant, stop, or exit targets with cones when needed.","Athlete starts tall enough to see the field but low enough to load hips and push the ground."],"execution_steps":["Bounce or hop in a small amplitude while keeping contacts quick and quiet.","Keep knees soft, heels barely kissing or hovering based on athlete level.","Maintain rhythm for the prescribed contacts, then stop before stiffness becomes sloppy."],"coach_cues":["Quick and quiet off the floor.","Tall posture, springy ankles.","Stop while it still feels crisp."],"athlete_cues":["Quick and quiet off the floor.","Tall posture, springy ankles.","Stop while it still feels crisp."],"breathing_cues":["Exhale through the plant or stick.","Do not hold the breath during braking.","Recover with calm nasal breathing between high-intent reps."],"common_faults":["Contacts getting loud or slow.","Knees locking out.","Shoulders bouncing excessively.","Athlete chasing fatigue instead of rhythm."],"quality_gate":["Athlete can repeat the rep on both sides with no pain and no visible loss of alignment.","Stops are quiet and controlled; exits are clean without false steps.","Coach can identify the intended angle or transition from the athlete’s shin and hip position."],"stop_signs":["Knee, groin, Achilles, hamstring, or low-back pain.","Loss of balance on two consecutive reps.","Noticeable limp, protective movement, or inability to decelerate safely.","Reaction drills become collisions or unsafe reaches."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["45-Degree Cut and Reaccelerate","5-Yard Acceleration Decel Stick"],"pairs_well_after":["Dynamic ankle rocks","A-skip","Snap-Down to Athletic Stick"],"good_for_sessions":["landing_prep","sprint_prep","general_warmup"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete has pain or a limp","Surface is slippery or crowded","Athlete cannot demonstrate a quiet stick or controlled plant at lower speed","Fatigue is high enough that posture and foot placement are deteriorating"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=j0nl5dWuqN4","https://www.youtube.com/watch?v=cQ9JP36zIq4"],"internal_notes":["Search/video references should be used to brief filming angles for Line Pogo Hops.","Prioritize front, side, and 45-degree views so knee-foot alignment, trunk angle, and exit step can be audited.","For soccer_ball or lacrosse_stick, add equipment key migration if the production taxonomy does not already include it."]}'::jsonb,
