-- Route Stem Break Series (route-stem-break-series)
UPDATE coaching.exercise SET
  name = 'Route Stem Break Series',
  description = 'Route Stem Break Series is a route running and offensive shiftiness drill. The athlete uses clear start, plant, stop, or exit targets to rehearse stem, sell, brake, and exit to multiple angles, emphasizing low hips, clean foot placement, aligned braking, and an immediate reacceleration or stable stick depending on the drill intent.',
  card_summary = 'Route Stem Break Series targets stem, sell, brake, and exit to multiple angles for athletes who need fast stops, sharp cuts, and explosive reacceleration. It was selected for football receivers, soccer players, lacrosse players, and other field-sport athletes who need dynamic shiftiness without sacrificing joint control.',
  coach_language = 'Primary subrole: perception_action_reactive_movement. Use this card for route running and offensive shiftiness. Coach the entry, plant, and exit as separate qualities before blending them into faster sport-like reps.',
  athlete_language = 'Brake clean, own the edge, then explode out.',
  movement_family = 'Route Break Mechanics',
  primary_phase_key = 'movement_intelligence',
  phase_subrole = 'perception_action_reactive_movement',
  primary_order_slot = 'route_stem_break_series',
  default_sets = 3,
  default_reps = 4,
  default_work_seconds = 25,
  default_rest_seconds = 45,
  est_seconds_per_set = 70,
  movement_requirements = '{"primary_joint_actions":["ankle_stiffness","knee_flexion_extension_control","hip_flexion_extension","hip_abduction_adduction_control","hip_internal_external_rotation","trunk_rotation_control"],"primary_tissues":["foot_intrinsics","calf_achilles_complex","quadriceps","hamstrings","gluteals","adductors"],"primary_motor_control_demands":["center_of_mass_control","edge_control","trunk_pelvis_alignment","braking_angle_ownership","plant_foot_orientation","inside_edge_loading","reacceleration_projection"],"postural_shape":"athletic stance with ribs stacked over pelvis, hips loaded, eyes up, and shin angle matched to intended direction","breathing_demand":"natural exhale through effort; no breath-holding during braking or cutting","balance_demand":"dynamic single-leg and split-stance balance","coordination_demand":"high timing demand: foot strike, hip load, trunk orientation, visual cue, and reacceleration must stay connected","impact_level":2}'::jsonb,
  coaching_execution = '{"movement_description":"Route Stem Break Series develops stem, sell, brake, and exit to multiple angles for field and court athletes who need abrupt stops, quick redirection, and explosive reacceleration while preserving posture and joint alignment.","setup":["Use a flat, dry surface with enough clear space for the prescribed approach and exit.","Mark start, plant, stop, or exit targets with cones when needed.","Athlete starts tall enough to see the field but low enough to load hips and push the ground."],"execution_steps":["Execute the Route Stem Break Series with the stated focus: stem, sell, brake, and exit to multiple angles.","Enter the rep with quiet feet and an active trunk; do not rush the setup.","Load the hip, knee, and ankle together; keep the foot tripod and knee tracking over the midfoot.","Finish by sticking, braking, or exiting with the first two steps clean and intentional.","Reset fully before the next rep so every attempt is a quality repetition, not conditioning by accident.","Use coach call, opponent movement, or sport implement only after the athlete demonstrates the base rhythm cleanly."],"coach_cues":["Brake before you turn.","Hips low, chest proud, eyes up.","Push the ground away; do not reach for the cone.","Quiet stick, violent exit.","Knee over midfoot; own the inside edge."],"athlete_cues":["Brake before you turn.","Hips low, chest proud, eyes up.","Push the ground away; do not reach for the cone."],"breathing_cues":["Exhale through the plant or stick.","Do not hold the breath during braking.","Recover with calm nasal breathing between high-intent reps."],"common_faults":["Extra gather steps before the plant.","Knee collapsing inside the foot during the stop or cut.","Torso rotating away from the intended exit.","Plant foot too narrow, too far ahead, or too turned out for the cut angle.","Turning the drill into conditioning volume instead of quality movement."],"quality_gate":["Athlete can repeat the rep on both sides with no pain and no visible loss of alignment.","Stops are quiet and controlled; exits are clean without false steps.","Coach can identify the intended angle or transition from the athlete’s shin and hip position."],"stop_signs":["Knee, groin, Achilles, hamstring, or low-back pain.","Loss of balance on two consecutive reps.","Noticeable limp, protective movement, or inability to decelerate safely.","Reaction drills become collisions or unsafe reaches."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Reactive cone drill","Planned COD output drill"],"pairs_well_after":["Dynamic warm-up","A-march","Line Hops"],"good_for_sessions":["sprint_prep","deceleration","reactive_agility"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete has pain or a limp","Surface is slippery or crowded","Athlete cannot demonstrate a quiet stick or controlled plant at lower speed","Fatigue is high enough that posture and foot placement are deteriorating"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=QEk95UCvmwg","https://www.youtube.com/watch?v=x8-eq7RNsaQ"],"internal_notes":["Search/video references should be used to brief filming angles for Route Stem Break Series.","Prioritize front, side, and 45-degree views so knee-foot alignment, trunk angle, and exit step can be audited.","For soccer_ball or lacrosse_stick, add equipment key migration if the production taxonomy does not already include it."]}'::jsonb,
  updated_at = now()
WHERE slug = 'route-stem-break-series';

