UPDATE coaching.exercise SET
  name = 'Tennis Ball Lateral Reaction',
  description = 'Tennis Ball Lateral Reaction is a reactive perception-action agility drill. The athlete uses clear start, plant, stop, or exit targets to rehearse reactive first step and lateral catch, emphasizing low hips, clean foot placement, aligned braking, and an immediate reacceleration or stable stick depending on the drill intent.',
  card_summary = 'Tennis Ball Lateral Reaction targets reactive first step and lateral catch for athletes who need fast stops, sharp cuts, and explosive reacceleration. It was selected for football receivers, soccer players, lacrosse players, and other field-sport athletes who need dynamic shiftiness without sacrificing joint control.',
  coach_language = 'Primary subrole: perception_action_reactive_movement. Use this card for reactive perception-action agility. Coach the entry, plant, and exit as separate qualities before blending them into faster sport-like reps.',
  athlete_language = 'Brake clean, own the edge, then explode out.',
  movement_family = 'Reactive Catch & Cut',
  primary_phase_key = 'movement_intelligence',
  phase_subrole = 'perception_action_reactive_movement',
  primary_order_slot = 'tennis_ball_lateral_reaction',
  default_sets = 3,
  default_reps = 4,
  default_work_seconds = 20,
  default_rest_seconds = 40,
  est_seconds_per_set = 60,
