  coaching_execution = '{"movement_description":"Tennis Ball Lateral Reaction develops reactive first step and lateral catch for field and court athletes who need abrupt stops, quick redirection, and explosive reacceleration while preserving posture and joint alignment.","setup":["Use a flat, dry surface with enough clear space for the prescribed approach and exit.","Mark start, plant, stop, or exit targets with cones when needed.","Athlete starts tall enough to see the field but low enough to load hips and push the ground."],"execution_steps":["Execute the Tennis Ball Lateral Reaction with the stated focus: reactive first step and lateral catch.","Enter the rep with quiet feet and an active trunk; do not rush the setup.","Load the hip, knee, and ankle together; keep the foot tripod and knee tracking over the midfoot.","Finish by sticking, braking, or exiting with the first two steps clean and intentional.","Reset fully before the next rep so every attempt is a quality repetition, not conditioning by accident.","Use coach call, opponent movement, or sport implement only after the athlete demonstrates the base rhythm cleanly."],"coach_cues":["Brake before you turn.","Hips low, chest proud, eyes up.","Push the ground away; do not reach for the cone.","Quiet stick, violent exit.","Knee over midfoot; own the inside edge."],"athlete_cues":["Brake before you turn.","Hips low, chest proud, eyes up.","Push the ground away; do not reach for the cone."],"breathing_cues":["Exhale through the plant or stick.","Do not hold the breath during braking.","Recover with calm nasal breathing between high-intent reps."],"common_faults":["Extra gather steps before the plant.","Knee collapsing inside the foot during the stop or cut.","Torso rotating away from the intended exit.","Plant foot too narrow, too far ahead, or too turned out for the cut angle.","Turning the drill into conditioning volume instead of quality movement."],"quality_gate":["Athlete can repeat the rep on both sides with no pain and no visible loss of alignment.","Stops are quiet and controlled; exits are clean without false steps.","Coach can identify the intended angle or transition from the athlete’s shin and hip position."],"stop_signs":["Knee, groin, Achilles, hamstring, or low-back pain.","Loss of balance on two consecutive reps.","Noticeable limp, protective movement, or inability to decelerate safely.","Reaction drills become collisions or unsafe reaches."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Reactive cone drill","Planned COD output drill"],"pairs_well_after":["Dynamic warm-up","A-march","Line Hops"],"good_for_sessions":["sprint_prep","deceleration","reactive_agility"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete has pain or a limp","Surface is slippery or crowded","Athlete cannot demonstrate a quiet stick or controlled plant at lower speed","Fatigue is high enough that posture and foot placement are deteriorating"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=o7MMD53XSdg","https://www.youtube.com/watch?v=i-NwDPUDlRQ"],"internal_notes":["Search/video references should be used to brief filming angles for Tennis Ball Lateral Reaction.","Prioritize front, side, and 45-degree views so knee-foot alignment, trunk angle, and exit step can be audited.","For soccer_ball or lacrosse_stick, add equipment key migration if the production taxonomy does not already include it."]}'::jsonb,
