  coaching_execution = '{"movement_description":"Rear-Foot Elevated Split Squat Iso Cut Position develops isometric single-leg force in cut-like angles for field and court athletes who need abrupt stops, quick redirection, and explosive reacceleration while preserving posture and joint alignment.","setup":["Place rear foot on a low box or bench.","Set front foot far enough forward to create a cut-like shin angle without heel lift.","Hold light dumbbells only if the athlete can maintain knee-over-midfoot alignment."],"execution_steps":["Descend into the target cut-like split squat angle.","Hold with front foot rooted and knee tracking over the middle toes.","Keep pelvis level and torso slightly inclined like a cutting posture.","Stand up smoothly or step out before alignment degrades."],"coach_cues":["Brake before you turn.","Hips low, chest proud, eyes up.","Push the ground away; do not reach for the cone.","Quiet stick, violent exit.","Knee over midfoot; own the inside edge."],"athlete_cues":["Brake before you turn.","Hips low, chest proud, eyes up.","Push the ground away; do not reach for the cone."],"breathing_cues":["Exhale through the plant or stick.","Do not hold the breath during braking.","Recover with calm nasal breathing between high-intent reps."],"common_faults":["Extra gather steps before the plant.","Knee collapsing inside the foot during the stop or cut.","Torso rotating away from the intended exit.","Plant foot too narrow, too far ahead, or too turned out for the cut angle.","Turning the drill into conditioning volume instead of quality movement."],"quality_gate":["Athlete can repeat the rep on both sides with no pain and no visible loss of alignment.","Stops are quiet and controlled; exits are clean without false steps.","Coach can identify the intended angle or transition from the athlete’s shin and hip position."],"stop_signs":["Knee, groin, Achilles, hamstring, or low-back pain.","Loss of balance on two consecutive reps.","Noticeable limp, protective movement, or inability to decelerate safely.","Reaction drills become collisions or unsafe reaches."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Resilience accessory work","Repeat COD Shuttle Intervals"],"pairs_well_after":["Output COD drills","Lateral Bound to Stick"],"good_for_sessions":["deceleration","resilience","sprint_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete has pain or a limp","Surface is slippery or crowded","Athlete cannot demonstrate a quiet stick or controlled plant at lower speed","Fatigue is high enough that posture and foot placement are deteriorating"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=RJtZomcGcYg","https://www.youtube.com/watch?v=4bNQITw0VdY"],"internal_notes":["Search/video references should be used to brief filming angles for Rear-Foot Elevated Split Squat Iso Cut Position.","Prioritize front, side, and 45-degree views so knee-foot alignment, trunk angle, and exit step can be audited.","For soccer_ball or lacrosse_stick, add equipment key migration if the production taxonomy does not already include it."]}'::jsonb,
