-- Short-Lever Copenhagen Plank (short-lever-copenhagen-plank)
UPDATE coaching.exercise SET
  name = 'Short-Lever Copenhagen Plank',
  description = 'Short-Lever Copenhagen Plank is a adductor and trunk resilience drill. The athlete uses clear start, plant, stop, or exit targets to rehearse adductor capacity for lateral cuts and groin resilience, emphasizing low hips, clean foot placement, aligned braking, and an immediate reacceleration or stable stick depending on the drill intent.',
  card_summary = 'Short-Lever Copenhagen Plank targets adductor capacity for lateral cuts and groin resilience for athletes who need fast stops, sharp cuts, and explosive reacceleration. It was selected for football receivers, soccer players, lacrosse players, and other field-sport athletes who need dynamic shiftiness without sacrificing joint control.',
  coach_language = 'Primary subrole: trunk_pelvis_anti_movement_control. Use this card for adductor and trunk resilience. Coach the entry, plant, and exit as separate qualities before blending them into faster sport-like reps.',
  athlete_language = 'Brake clean, own the edge, then explode out.',
  movement_family = 'Adductor & Trunk Resilience',
  primary_phase_key = 'resilience',
  phase_subrole = 'trunk_pelvis_anti_movement_control',
  primary_order_slot = 'copenhagen_adductor_resilience',
  default_sets = 2,
  default_reps = NULL,
  default_work_seconds = 20,
  default_rest_seconds = 45,
  est_seconds_per_set = 70,
  movement_requirements = '{"primary_joint_actions":["hip_adduction_abduction_control","lateral_trunk_flexion_control"],"primary_tissues":["adductors","obliques","gluteus_medius"],"primary_motor_control_demands":["pelvis_stack","anti_lateral_flexion","adductor_tension_control"],"postural_shape":"athletic stance with ribs stacked over pelvis, hips loaded, eyes up, and shin angle matched to intended direction","breathing_demand":"natural exhale through effort; no breath-holding during braking or cutting","balance_demand":"dynamic single-leg and split-stance balance","coordination_demand":"high timing demand: foot strike, hip load, trunk orientation, visual cue, and reacceleration must stay connected","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Short-Lever Copenhagen Plank develops adductor capacity for lateral cuts and groin resilience for field and court athletes who need abrupt stops, quick redirection, and explosive reacceleration while preserving posture and joint alignment.","setup":["Set a bench or box at knee height or lower.","Place top knee or lower leg on the support and bottom forearm under shoulder.","Stack ribs, pelvis, and shoulders in a straight side-plank line."],"execution_steps":["Lift hips until body forms a straight line.","Press top leg into the bench and gently lift bottom leg or keep it supported as needed.","Hold without rib flare, hip sag, or groin pain.","Lower under control and switch sides."],"coach_cues":["Long line from ear to ankle.","Press the bench away with the top leg.","No hip sag, no groin pinch."],"athlete_cues":["Long line from ear to ankle.","Press the bench away with the top leg.","No hip sag, no groin pinch."],"breathing_cues":["Exhale through the plant or stick.","Do not hold the breath during braking.","Recover with calm nasal breathing between high-intent reps."],"common_faults":["Hip sagging toward the floor.","Top leg gripping with pain instead of strong tension.","Shoulder shrugging into ear.","Breath held for the full hold."],"quality_gate":["Athlete can repeat the rep on both sides with no pain and no visible loss of alignment.","Stops are quiet and controlled; exits are clean without false steps.","Coach can identify the intended angle or transition from the athlete’s shin and hip position."],"stop_signs":["Knee, groin, Achilles, hamstring, or low-back pain.","Loss of balance on two consecutive reps.","Noticeable limp, protective movement, or inability to decelerate safely.","Reaction drills become collisions or unsafe reaches."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Lateral Bound to Stick","45-Degree Cut and Reaccelerate"],"pairs_well_after":["Line Pogo Hops","Drop Squat to Athletic Stance","Lateral Weight Shift"],"good_for_sessions":["control_landing","deceleration","resilience"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Athlete has pain or a limp","Surface is slippery or crowded","Athlete cannot demonstrate a quiet stick or controlled plant at lower speed","Fatigue is high enough that posture and foot placement are deteriorating"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["https://www.youtube.com/watch?v=yByUFuQsgCg","https://www.youtube.com/watch?v=YRRnnZsRs9U"],"internal_notes":["Search/video references should be used to brief filming angles for Short-Lever Copenhagen Plank.","Prioritize front, side, and 45-degree views so knee-foot alignment, trunk angle, and exit step can be audited.","For soccer_ball or lacrosse_stick, add equipment key migration if the production taxonomy does not already include it."]}'::jsonb,
  updated_at = now()
WHERE slug = 'short-lever-copenhagen-plank';

