);

-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic shiftiness and COD.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('line-pogo-hops', 'Line Pogo Hops improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during two-foot vertical stiffness before cuts. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in prepare_and_access / potentiate_bridge because the drill’s main adaptation is elastic stiffness and foot reactivity. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Use in Prepare & Access as a short potentiation bridge before sprint, COD, jump, or reactive agility work.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('lateral-line-pogo-hops', 'Lateral Line Pogo Hops improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during side-to-side ankle stiffness. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in prepare_and_access / potentiate_bridge because the drill’s main adaptation is elastic stiffness and foot reactivity. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Use in Prepare & Access as a short potentiation bridge before sprint, COD, jump, or reactive agility work.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('forward-back-line-hops', 'Forward-Back Line Hops improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during brake-and-pop rhythm in the sagittal plane. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in prepare_and_access / potentiate_bridge because the drill’s main adaptation is elastic stiffness and foot reactivity. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Use in Prepare & Access as a short potentiation bridge before sprint, COD, jump, or reactive agility work.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('single-leg-line-hop-and-stick', 'Single-Leg Line Hop and Stick improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during single-leg stiffness plus stick ownership. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in movement_intelligence / balance_coordination_rhythm because the drill’s main adaptation is elastic stiffness and foot reactivity. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place after warm-up and before true Output. Keep reps crisp; the goal is coordination, perception, and clean timing, not fatigue.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('snap-down-to-athletic-stick', 'Snap-Down to Athletic Stick improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during fast hip drop into braking posture. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in resilience / landing_braking_control because the drill’s main adaptation is braking and landing foundations. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place after technical warm-up or after the primary Output/Capacity work as a braking, landing, or tissue-control block.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('single-leg-snap-down-stick', 'Single-Leg Snap-Down Stick improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during single-leg force absorption and knee-foot alignment. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in resilience / landing_braking_control because the drill’s main adaptation is braking and landing foundations. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place after technical warm-up or after the primary Output/Capacity work as a braking, landing, or tissue-control block.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('drop-landing-to-lateral-stick', 'Drop Landing to Lateral Stick improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during drop absorption with lateral ownership. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in resilience / landing_braking_control because the drill’s main adaptation is braking and landing foundations. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place after technical warm-up or after the primary Output/Capacity work as a braking, landing, or tissue-control block.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('low-box-drop-to-stick', 'Low Box Drop to Stick improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during vertical force absorption before harder cuts. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in resilience / landing_braking_control because the drill’s main adaptation is braking and landing foundations. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place after technical warm-up or after the primary Output/Capacity work as a braking, landing, or tissue-control block.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('lateral-bound-to-stick', 'Lateral Bound to Stick improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during lateral projection plus controlled landing. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in output / elastic_stiffness_plyometric_rudiments because the drill’s main adaptation is lateral power and stick control. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place in the Output block after warm-up, movement prep, and basic braking rehearsal. Use low volume, high intent, and full rest before strength or conditioning.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('skater-bound-to-stick', 'Skater Bound to Stick improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during rhythmical lateral projection and re-centering. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in output / elastic_stiffness_plyometric_rudiments because the drill’s main adaptation is lateral power and stick control. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place in the Output block after warm-up, movement prep, and basic braking rehearsal. Use low volume, high intent, and full rest before strength or conditioning.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('5-yard-acceleration-decel-stick', '5-Yard Acceleration Decel Stick improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during first exposure to planned high-intent stopping. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in output / deceleration_cod_power because the drill’s main adaptation is linear braking and stopping ability. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place in the Output block after warm-up, movement prep, and basic braking rehearsal. Use low volume, high intent, and full rest before strength or conditioning.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('10-yard-build-up-to-breakdown', '10-Yard Build-Up to Breakdown improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during longer approach velocity into breakdown steps. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in output / deceleration_cod_power because the drill’s main adaptation is linear braking and stopping ability. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place in the Output block after warm-up, movement prep, and basic braking rehearsal. Use low volume, high intent, and full rest before strength or conditioning.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('backpedal-to-decel-stick', 'Backpedal to Decel Stick improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during defensive back and field sport braking. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in output / deceleration_cod_power because the drill’s main adaptation is backward-to-forward braking. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place in the Output block after warm-up, movement prep, and basic braking rehearsal. Use low volume, high intent, and full rest before strength or conditioning.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('lateral-shuffle-to-braking-stick', 'Lateral Shuffle to Braking Stick improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during side shuffle braking with hips low. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in output / deceleration_cod_power because the drill’s main adaptation is lateral braking and stopping ability. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place in the Output block after warm-up, movement prep, and basic braking rehearsal. Use low volume, high intent, and full rest before strength or conditioning.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('closeout-deceleration', 'Closeout Deceleration improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during sprint into controlled closeout posture. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in output / deceleration_cod_power because the drill’s main adaptation is linear-to-defensive braking. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place in the Output block after warm-up, movement prep, and basic braking rehearsal. Use low volume, high intent, and full rest before strength or conditioning.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('curved-run-decel', 'Curved Run Decel improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during arc run into balanced stop. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in output / deceleration_cod_power because the drill’s main adaptation is curved approach braking. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place in the Output block after warm-up, movement prep, and basic braking rehearsal. Use low volume, high intent, and full rest before strength or conditioning.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
  ('45-degree-cut-and-reaccelerate', '45-Degree Cut and Reaccelerate improves the athlete’s ability to coordinate the foot, ankle, knee, hip, trunk, and visual system during game-realistic shallow redirection. Field-sport agility depends on producing force quickly, absorbing force safely, and reorienting the body without extra steps; this drill isolates one piece of that chain and then links it to a usable athletic action.', 'Belongs in output / deceleration_cod_power because the drill’s main adaptation is planned cut and reacceleration. The placement respects the Vortex rule that high-intent speed, COD, and reactive work must stay fresh, while control and tissue-capacity work sit in resilience or capacity rather than being disguised as warm-up conditioning.', 'Place in the Output block after warm-up, movement prep, and basic braking rehearsal. Use low volume, high intent, and full rest before strength or conditioning.', 'Most common error is adding too many reps, too little rest, or too much speed before the athlete can brake and align. Do not turn this into a fatigue circuit when the goal is speed, perception, or clean COD mechanics.', 'Scale first by speed, amplitude, decision complexity, and cut angle. Add velocity, sharper angles, defenders, balls, sticks, or resistance only after the athlete can show quiet stops and clean exits on both sides.'),
