-- Agility / Shiftiness cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'agility_shiftiness_readiness',
  NULL,
  'Agility / Shiftiness without pre-fatigue or wrong phase intent',
  'COD, reactive cuts, elastic prep, and sport-specific shiftiness drills must match phase intent — fresh for Output/Skill, controlled for Resilience, and never disguised conditioning in Prepare & Access.',
  'Agility / Shiftiness cards span elastic prep, landing sticks, pre-planned COD, reactive cuts, sport routes, and repeat shuttles for field and court athletes who need fast stops, sharp redirection, and explosive reacceleration.',
  'Shiftiness depends on stiffness, braking, perception, and joint alignment. Poor placement, short rest, or progression before linear braking raises injury risk and trains sloppy plants.',
  'Master sticks and elastic prep before COD power; use full rest on Output cuts; keep Skill reactive work submaximal; place repeat shuttles in Sustained Capacity — not Output.',
  'Do not program high-intent COD after conditioning, use shuttle-style short rest in Output, or hide fatigue circuits in Prepare & Access when the goal is speed and clean mechanics.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
